section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/persona-building.json",
  "title": "Persona Building",
  "type": "object",
  "required": [
    "artefact_id",
    "interviews_count",
    "clusters",
    "primary_persona",
    "negative_persona",
    "validation_cohort",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "interviews_count": {
      "type": "number",
      "description": "must be >=10 grounded interviews",
      "minimum": 0
    },
    "clusters": {
      "type": "array",
      "description": "{goal, frustrations, behaviours, evidence}",
      "minItems": 1
    },
    "primary_persona": {
      "type": "object",
      "description": "single primary archetype"
    },
    "negative_persona": {
      "type": "object",
      "description": "explicit do-not-design-for persona"
    },
    "validation_cohort": {
      "type": "object",
      "description": "real cohort behaviour vs persona claims"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
